#include <imgui.h>

void DrawMenuExample() {
    static bool show_scene = true;
    static bool show_props = true;
    static bool show_console = false;
    static bool can_save = false;
    static int selected_action = -1;

    ImGui::Begin("Editor Shell", nullptr, ImGuiWindowFlags_MenuBar);
    if (ImGui::BeginMenuBar()) {
        if (ImGui::BeginMenu("File")) {
            if (ImGui::BeginMenu("Import")) {
                if (ImGui::MenuItem("FBX")) { selected_action = 0; }
                if (ImGui::MenuItem("glTF")) { selected_action = 1; }
                if (ImGui::MenuItem("Texture Folder")) { selected_action = 2; }
                ImGui::EndMenu();
            }
            ImGui::Separator();
            ImGui::MenuItem("Save", "Ctrl+S", false, can_save);
            if (ImGui::MenuItem("Save As")) { selected_action = 3; }
            if (ImGui::MenuItem("Exit")) { selected_action = 4; }
            ImGui::EndMenu();
        }
        if (ImGui::BeginMenu("Edit")) {
            ImGui::MenuItem("Undo", "Ctrl+Z");
            ImGui::MenuItem("Redo", "Ctrl+Y", false, false);
            ImGui::MenuItem("Duplicate", "Ctrl+D");
            ImGui::EndMenu();
        }
        if (ImGui::BeginMenu("View")) {
            ImGui::MenuItem("Scene Panel", nullptr, &show_scene);
            ImGui::MenuItem("Properties", nullptr, &show_props);
            ImGui::MenuItem("Console", nullptr, &show_console);
            ImGui::EndMenu();
        }
        if (ImGui::BeginMenu("Developer")) {
            ImGui::MenuItem("Show Metrics");
            ImGui::MenuItem("Reload Shaders");
            ImGui::EndMenu();
        }
        ImGui::EndMenuBar();
    }

    ImGui::Selectable("Player.mesh");
    if (ImGui::BeginPopupContextItem("asset_context")) {
        if (ImGui::MenuItem("Focus")) { selected_action = 5; }
        if (ImGui::MenuItem("Rename")) { selected_action = 6; }
        if (ImGui::MenuItem("Delete", nullptr, false, false)) { selected_action = 7; }
        ImGui::EndPopup();
    }

    ImGui::Text("آخر إجراء: %d", selected_action);
    ImGui::Text("الحالات: Scene=%s / Properties=%s / Console=%s", show_scene ? "On" : "Off", show_props ? "On" : "Off", show_console ? "On" : "Off");
    ImGui::End();
}

