#include <imgui.h>

void DrawDockingWorkspaceExample() {
    static bool show_hierarchy = true;
    static bool show_inspector = true;
    static bool show_console = true;
    static bool show_scene = true;
    static int selected_entity = 0;
    static float inspector_position[3] = {0.0f, 0.0f, 0.0f};
    static float inspector_tint[4] = {0.85f, 0.73f, 0.28f, 1.0f};

    ImGuiIO& io = ImGui::GetIO();
    io.ConfigFlags |= ImGuiConfigFlags_DockingEnable;

    ImGui::DockSpaceOverViewport();

    if (ImGui::BeginMainMenuBar()) {
        if (ImGui::BeginMenu("File")) {
            ImGui::MenuItem("New Scene");
            ImGui::MenuItem("Save", "Ctrl+S");
            ImGui::MenuItem("Exit");
            ImGui::EndMenu();
        }
        if (ImGui::BeginMenu("View")) {
            ImGui::MenuItem("Scene", nullptr, &show_scene);
            ImGui::MenuItem("Hierarchy", nullptr, &show_hierarchy);
            ImGui::MenuItem("Inspector", nullptr, &show_inspector);
            ImGui::MenuItem("Console", nullptr, &show_console);
            ImGui::EndMenu();
        }
        if (ImGui::BeginMenu("Developer")) {
            ImGui::MenuItem("Metrics");
            ImGui::MenuItem("Reload Assets");
            ImGui::EndMenu();
        }
        ImGui::EndMainMenuBar();
    }

    if (show_scene) {
        ImGui::Begin("Scene");
        ImGui::Text("Viewport placeholder");
        ImGui::Button("Play", ImVec2(82.0f, 0.0f));
        ImGui::SameLine();
        ImGui::Button("Pause", ImVec2(82.0f, 0.0f));
        ImGui::End();
    }

    if (show_hierarchy) {
        ImGui::Begin("Hierarchy");
        if (ImGui::Selectable("Player", selected_entity == 0)) selected_entity = 0;
        if (ImGui::Selectable("Key Light", selected_entity == 1)) selected_entity = 1;
        if (ImGui::Selectable("Ground", selected_entity == 2)) selected_entity = 2;
        ImGui::End();
    }

    if (show_inspector) {
        ImGui::Begin("Inspector");
        ImGui::Text("Selected entity: %d", selected_entity);
        ImGui::DragFloat3("Position", inspector_position);
        ImGui::ColorEdit4("Tint", inspector_tint);
        ImGui::End();
    }

    if (show_console) {
        ImGui::Begin("Console");
        ImGui::Text("[Info] Scene loaded.");
        ImGui::Text("[Warn] Shadow atlas resized.");
        ImGui::End();
    }
}

