#include <imgui.h>
#include <stdint.h>

void DrawNestedMediaMenusExample() {
    static int selected_vehicle = 0;
    static ImTextureID thumbs[] = {
        (ImTextureID)(intptr_t)11,
        (ImTextureID)(intptr_t)12,
        (ImTextureID)(intptr_t)13
    };
    static const char* names[] = {"Roadster", "Coupe", "Track GT"};

    ImGui::Begin("Media Menus", nullptr, ImGuiWindowFlags_MenuBar);
    if (ImGui::BeginMenuBar()) {
        if (ImGui::BeginMenu("Assets")) {
            if (ImGui::BeginMenu("Vehicles")) {
                if (ImGui::BeginMenu("Sports")) {
                    for (int i = 0; i < 3; ++i) {
                        ImGui::PushID(i);
                        ImGui::Image(thumbs[i], ImVec2(48.0f, 32.0f));
                        ImGui::SameLine();
                        if (ImGui::MenuItem(names[i], nullptr, selected_vehicle == i)) {
                            selected_vehicle = i;
                        }
                        ImGui::PopID();
                    }
                    ImGui::EndMenu();
                }
                if (ImGui::BeginMenu("Utility")) {
                    ImGui::MenuItem("Pickup");
                    ImGui::MenuItem("Support Van");
                    ImGui::EndMenu();
                }
                ImGui::EndMenu();
            }
            if (ImGui::BeginMenu("Themes")) {
                if (ImGui::BeginMenu("Studio")) {
                    ImGui::MenuItem("Cobalt");
                    ImGui::MenuItem("Amber");
                    ImGui::EndMenu();
                }
                ImGui::EndMenu();
            }
            ImGui::EndMenu();
        }
        ImGui::EndMenuBar();
    }

    ImGui::Text("Selected vehicle: %s", names[selected_vehicle]);
    ImGui::Text("Last path: Assets > Vehicles > Sports");
    ImGui::End();
}
